import{_ as a,o as r,c as t,a3 as o}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"55. Travelling Allowance Use Of Private Vehicle","description":"","frontmatter":{"title":"55. Travelling Allowance Use Of Private Vehicle","eba":"Doctors in Training 2022-2026","topics":["hours","on-call","allowances","travel"]},"headers":[],"relativePath":"ebas/doctors-in-training/allowances/55-travelling-allowance-use-of-private-vehicle.md","filePath":"ebas/doctors-in-training/allowances/55-travelling-allowance-use-of-private-vehicle.md"}'),n={name:"ebas/doctors-in-training/allowances/55-travelling-allowance-use-of-private-vehicle.md"};function l(i,e,s,c,p,h){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="_55-travelling-allowance-use-of-private-vehicle" tabindex="-1">55. Travelling Allowance Use Of Private Vehicle <a class="header-anchor" href="#_55-travelling-allowance-use-of-private-vehicle" aria-label="Permalink to &quot;55. Travelling Allowance Use Of Private Vehicle&quot;">​</a></h1><p><strong>55.1</strong> The provisions of this clause 55 are to be read in conjunction with <a href="/eba/ebas/doctors-in-training/hours-of-work/39-recall-return-to-workplace.html">clause 39</a> (Recall).</p><p><strong>55.2</strong> Where a Doctor is required to use personal transport in the performance of his or her duties (including recall travel pursuant to <a href="/eba/ebas/doctors-in-training/hours-of-work/39-recall-return-to-workplace.html">clause 39</a>) they must receive a Travelling Allowance per kilometre in accordance with <a href="/eba/ebas/doctors-in-training/appendices/2-doctors-in-training-remuneration-allowances-and-deductions.html">Appendix 2</a>, Table 2.3.</p><p><strong>55.3</strong> The Doctor is responsible for maintaining records sufficient to support any claim made pursuant to this clause 55.</p><p><strong>55.4</strong> A Doctor who is recalled and who has not used personal transport must be provided with suitable return transport at the Health Service’s expense.</p>',5)])])}const v=a(n,[["render",l]]);export{d as __pageData,v as default};
